void MOD_mkXsimTop::vcd_submodules(tVCDDumpType dt, unsigned int levels, MOD_mkXsimTop &backing)
{
  INST_lMMUIndicationOutput.dump_VCD(dt, levels, backing.INST_lMMUIndicationOutput);
  INST_lMMURequestInput.dump_VCD(dt, levels, backing.INST_lMMURequestInput);
  INST_lMMU_mmu.dump_VCD(dt, levels, backing.INST_lMMU_mmu);
  INST_lMemServerIndicationOutput.dump_VCD(dt, levels, backing.INST_lMemServerIndicationOutput);
  INST_lMemServerRequestInput.dump_VCD(dt, levels, backing.INST_lMemServerRequestInput);
  INST_top.dump_VCD(dt, levels, backing.INST_top);
}
